import{_ as r,o as t,c as s,ag as e}from"./chunks/framework.ETe_P6d1.js";const p="/kaiping-reports/assets/1.C0TCGWIR.jpg",i="/kaiping-reports/assets/2.Cx1k7XM-.jpg",o="/kaiping-reports/assets/3.ms5FqdGo.jpg",n="/kaiping-reports/assets/4.pmg-aTjr.jpg",l="/kaiping-reports/assets/5.ayhsQR1a.jpg",_="/kaiping-reports/assets/6.5JUrb0I5.jpg",c="/kaiping-reports/assets/7.LCEM6cPy.jpg",h="/kaiping-reports/assets/8.DdmvIr_d.jpg",d="/kaiping-reports/assets/10.-Mnwybtu.jpg",m="/kaiping-reports/assets/11.Da4yJqKp.jpg",g="/kaiping-reports/assets/12.B7OHkdBI.jpg",b="/kaiping-reports/assets/13.DIZi7dF3.jpg",k="/kaiping-reports/assets/14.wpwbYpbc.jpg",u="/kaiping-reports/assets/15.9BGd92o4.jpg",q="/kaiping-reports/assets/16.fJAbCfiC.jpg",f="/kaiping-reports/assets/17.Z8iwd1Qp.jpg",S=JSON.parse('{"title":"中西建筑文化的对话：开平近代建筑中建筑语言融合的调研报告——以立园、仓东村与赤坎古镇为例","description":"","frontmatter":{"title":"中西建筑文化的对话：开平近代建筑中建筑语言融合的调研报告——以立园、仓东村与赤坎古镇为例"},"headers":[],"relativePath":"reports/陈升逸/陈升逸_调研报告.md","filePath":"reports/陈升逸/陈升逸_调研报告.md"}'),P={name:"reports/陈升逸/陈升逸_调研报告.md"};function x(j,a,C,T,I,B){return t(),s("div",null,[...a[0]||(a[0]=[e('<h1 id="中西建筑文化的对话-开平近代建筑中建筑语言融合的调研报告——以立园、仓东村与赤坎古镇为例" tabindex="-1">中西建筑文化的对话：开平近代建筑中建筑语言融合的调研报告——以立园、仓东村与赤坎古镇为例 <a class="header-anchor" href="#中西建筑文化的对话-开平近代建筑中建筑语言融合的调研报告——以立园、仓东村与赤坎古镇为例" aria-label="Permalink to &quot;中西建筑文化的对话：开平近代建筑中建筑语言融合的调研报告——以立园、仓东村与赤坎古镇为例&quot;">​</a></h1><h1 id="作者-陈升逸" tabindex="-1">作者：陈升逸 <a class="header-anchor" href="#作者-陈升逸" aria-label="Permalink to &quot;作者：陈升逸&quot;">​</a></h1><p>考察地点：广东省江门市开平市<br> 考察时间：2026年4月1日至2026年4月2日<br> 指导教师：石拓 教授</p><h1 id="一、引言-从-中西合璧-到-文化对话" tabindex="-1">一、引言：从“中西合璧”到“文化对话” <a class="header-anchor" href="#一、引言-从-中西合璧-到-文化对话" aria-label="Permalink to &quot;一、引言：从“中西合璧”到“文化对话”&quot;">​</a></h1><p>开平近代建筑常被概括为“中西合璧”的典型样本，但若仅停留在风格描述层面，便容易将其价值理解为西式构件与中式空间的简单拼接。结合本次实地调研可以发现，开平建筑真正值得关注之处，不仅在于拱券、柱式、山花、灰塑、题额、瓦顶等形式要素的并存，更在于这些建筑语言如何在侨乡社会背景中被重新组织，并进一步转化为身份表达、礼制延续与街区形象建构的媒介。</p><p>本报告以“中西建筑文化的对话”为核心主题，以“建筑语言与文化表达”为主要分析线索，选取立园住宅、仓东村祠堂和赤坎古镇骑楼群三类案例进行比较。文章试图回答如下问题：在开平近代建筑中，中西建筑语言并非彼此对立的两套体系，它们如何在不同建筑类型中被重新组合，并形成具有地方性的文化表达机制？围绕这一问题，本文将从建筑语言的构成现象入手，进而分析其背后的社会意义与遗产价值。</p><h1 id="二、建筑语言融合-中西建筑文化在形式层面的相遇" tabindex="-1">二、建筑语言融合：中西建筑文化在形式层面的相遇 <a class="header-anchor" href="#二、建筑语言融合-中西建筑文化在形式层面的相遇" aria-label="Permalink to &quot;二、建筑语言融合：中西建筑文化在形式层面的相遇&quot;">​</a></h1><h3 id="_2-1-立园-中式统摄下的折中表达" tabindex="-1">2.1 立园：中式统摄下的折中表达 <a class="header-anchor" href="#_2-1-立园-中式统摄下的折中表达" aria-label="Permalink to &quot;2.1 立园：中式统摄下的折中表达&quot;">​</a></h3><p>立园中的住宅建筑最能体现开平近代建筑在形式层面的复杂性。其共同特点并非单纯“西式化”，而是在总体秩序上仍保留中式建筑的礼序意识，同时在立面与构件层面吸收近代西式语汇。以泮立楼、泮文楼为例，建筑立面采用较完整的三段式构图，中部可见阳台、拱券与柱廊等近代构件，但其上部并非典型西式山花，而是更接近中式牌坊式收头，并配合明显的青瓦屋顶。</p><p>相比之下，炯庐、明庐的上部山花更接近巴洛克式处理，装饰性更强，西式立面语言也更为突出。两者的差异说明，立园内部并不存在单一的“中西合璧”模式，而是与建筑主人的身份地位、住宅功能和审美取向密切相关，因而形成了不同层次、不同侧重的融合路径。换言之，建筑构造与设计语言的差异，并不只是形式选择的结果，也反映了居住者在家族秩序、社会声望与自我展示上的不同诉求。这种差异本身表明，中西建筑文化在这里并非被动叠加，而是经由选择、调适与地方化转译后形成的结果。</p><p><img src="'+p+'" alt="((图1))"><img src="'+i+'" alt="((图2))"></p><h3 id="_2-2-毓培别墅-洋楼形象中的地方重组" tabindex="-1">2.2 毓培别墅：洋楼形象中的地方重组 <a class="header-anchor" href="#_2-2-毓培别墅-洋楼形象中的地方重组" aria-label="Permalink to &quot;2.2 毓培别墅：洋楼形象中的地方重组&quot;">​</a></h3><p>若说泮立楼、泮文楼体现的是“中式统摄下的折中表达”，那么立园中的毓培别墅则更接近一种“洋楼化”的近代住宅形象。毓培别墅采用竖向突出的塔楼体量，外部可见拱形入口、金属格栅门、洗石子或水刷石外墙、矩形高窗、防护窗及简化线脚等做法，整体呈现出鲜明的异域感和近代秩序感。但其屋顶仍保留中式塔楼收头，说明其并非对西式别墅样式的简单照搬，而是在地方工艺与空间习惯中对外来形式进行再组织。</p><p>从内部空间看，毓培别墅同样呈现中西并置的特征。拱券门洞、走廊空间、木楼梯、几何拼花地坪、高窗采光与阁楼式斜顶空间等近代住宅要素，与中式家具陈设和传统生活设施并存。这种并置并未造成割裂，反而显示出华侨住宅在“现代生活方式”与“本土家族秩序”之间寻求平衡的过程。建筑因此不只是生活容器，也成为归乡华侨展示身份、财富与文化经验的可视化媒介。</p><p><img src="'+o+'" alt="((图3))"><img src="'+n+'" alt="((图4))"><img src="'+l+'" alt="((图5))"></p><h3 id="_2-3-仓东村公祠-礼制空间中的近代更新" tabindex="-1">2.3 仓东村公祠：礼制空间中的近代更新 <a class="header-anchor" href="#_2-3-仓东村公祠-礼制空间中的近代更新" aria-label="Permalink to &quot;2.3 仓东村公祠：礼制空间中的近代更新&quot;">​</a></h3><p>与立园住宅不同，仓东村的秉文谢公祠、侯成谢公祠等建筑所面对的并非家庭内部生活，而是宗族公共生活。因此，其建筑语言融合更集中体现为礼制框架中的近代更新。公祠在空间结构上仍保持较强的中轴性、厅堂秩序和祭祀功能，祖龛、对联、书画装饰及木构屋架仍是内部空间的核心内容；但在外立面处理上，则吸收了罗马拱券、圆窗、柱头、山花、灰塑和壁画彩绘等近代语汇。</p><p>这种变化并不能简单理解为“祠堂西化”。更准确地说，公祠是在维持传统礼制内核的前提下，通过吸收近代立面语汇，呈现出更强的公共展示性与时代表征。这并非一种简单替代，而是传统宗族建筑借助近代形式重塑其外部形象的过程。因此，这类建筑既是礼制空间，也是近代乡村社会自我展示秩序的一种方式。</p><p><img src="'+_+'" alt="((图6))"><img src="'+c+'" alt="((图7))"></p><h3 id="_2-4-赤坎骑楼-面向街道的公共表达" tabindex="-1">2.4 赤坎骑楼：面向街道的公共表达 <a class="header-anchor" href="#_2-4-赤坎骑楼-面向街道的公共表达" aria-label="Permalink to &quot;2.4 赤坎骑楼：面向街道的公共表达&quot;">​</a></h3><p>赤坎古镇的骑楼与沿街商住建筑，则代表了另一种更具公共性的中西建筑文化对话方式。此类建筑首先服务于商业街道，因此其建筑语言更强调连续界面、节奏秩序和视觉识别。首层柱廊回应岭南气候条件和沿街通行需求，上部则通过阳台、栏板、线脚、山花与女儿墙等元素组织立面，使单体建筑既能融入整体街景，又能保留一定的个体特征。</p><p>与住宅和祠堂相比，骑楼建筑中的西式构件更具公共展示性。它们不主要服务于家庭伦理或祭祀秩序，而是服务于街道形象与商业传播。因此，这里的中西融合更像是一种面向公众的城市界面语言。拱券、柱廊和装饰山花经过地方化处理后，不再只是西方样式的复制，而成为侨乡近代商业建筑最具识别度的地方符号。</p><p><img src="'+h+'" alt="((图8))"></p><h1 id="三、从形式到意义-建筑语言如何转化为文化表达" tabindex="-1">三、从形式到意义：建筑语言如何转化为文化表达 <a class="header-anchor" href="#三、从形式到意义-建筑语言如何转化为文化表达" aria-label="Permalink to &quot;三、从形式到意义：建筑语言如何转化为文化表达&quot;">​</a></h1><p>若只从外观出发，开平近代建筑似乎只是“中式空间加上西式立面”或“西式构件嵌入传统建筑”的形式现象。但通过案例比较可以发现，建筑语言之所以重要，不在于其本身有多少装饰性，而在于这些形式在长期使用和社会认知中被赋予了明确的文化意义。换言之，开平建筑的核心价值不只是“看起来中西合璧”，而是建筑语言逐渐从装饰层面转化为文化表达层面。</p><p>在住宅建筑中，这种表达首先指向华侨身份的建构。以泮立楼为例，其建筑主体已明显采用近代洋楼的立面组织方式，中部可见阳台、拱券、柱廊等西式构件，整体呈现出较强的近代住宅特征。但在这一西式立面框架之上，建筑顶部并未继续采用典型的西式山花收头，而是融入了青瓦屋顶与带有牌坊意象的山花处理。也就是说，泮立楼并不是单纯以西式形式覆盖传统住宅，而是在近代洋楼结构的基础上，有意识地嵌入中式建筑语言，使建筑在外观上同时具有“洋楼”的现代感与“门第建筑”的传统象征意味。</p><p><img src="'+d+'" alt="((图10))"><img src="'+m+'" alt="((图11))"></p><p>这种中式语言的融入并非装饰性的附加。牌坊在中国传统建筑语境中本就与门第、功名和家族荣耀密切相关，具有明确的象征意义；青瓦屋顶则进一步强化了建筑与本土建造传统之间的联系。当这些元素被置于近代洋楼立面的顶部时，它们所传递的便不再只是单纯的传统意象，而是一种经过重组后的身份表达：建筑一方面借助西式立面传达华侨的经济实力、海外经验与现代生活方式，另一方面又通过牌坊式山花、瓦面屋顶及整体礼序感，将这种现代身份重新纳入家族门第与本土文化的表达体系之中。因此，泮立楼所体现的并不是表层的样式拼接，而是通过建筑语言融合来调和“现代身份”与“传统归属”的文化对话。</p><p>在祠堂建筑中，建筑语言融合更多体现为礼制秩序的外化更新。公祠原本就是宗族社会中最具象征性的空间，其意义建立在祖先崇敬、祭祀活动与公共议事之上。近代以来，拱券、柱头、山花和灰塑等新形式被纳入祠堂界面，并没有改变其礼制核心，却显著强化了其公共可见性与时代特征。也就是说，中西建筑文化在这里的对话，服务的并非私人身份，而是宗族整体形象的重塑。</p><p><img src="'+g+'" alt="((图12))"><img src="'+b+'" alt="((图13))"></p><p>在赤坎骑楼中，建筑语言融合则指向商业现代性与街区公共形象。骑楼建筑面向的是街道、行人和市场活动，因此其文化表达具有明显的外向性。连续柱廊和上部阳台共同形成可阅读的街景秩序，装饰性线脚和山花则强化了商业建筑的识别性。相比住宅和祠堂，这里的建筑语言更少依赖室内礼序，而更强调立面作为公共传播媒介的作用。它所塑造的不是单一家族或宗族的形象，而是一种整体性的近代侨乡城镇气质。</p><p><img src="'+k+'" alt="((图14))"><img src="'+u+'" alt="((图15))"><img src="'+q+'" alt="((图16))"><img src="'+f+'" alt="((图17))"></p><p>由此可见，同样是中西建筑语言的融合，在住宅、祠堂和骑楼中却指向不同的文化对象：住宅面向家族身份，祠堂面向宗族礼序，骑楼面向公众与市场。正因如此，开平近代建筑不能被笼统理解为“华侨建筑风格”的统一展示，而应被看作不同社会关系在建筑中的具体投射。中西建筑文化的对话并非抽象概念，而是通过具体的形式重组进入不同类型建筑，并最终转化为差异化的文化表达机制。</p><h1 id="四、批判性思考-遗产保护中应避免只见-样式-不见-机制" tabindex="-1">四、批判性思考：遗产保护中应避免只见“样式”不见“机制” <a class="header-anchor" href="#四、批判性思考-遗产保护中应避免只见-样式-不见-机制" aria-label="Permalink to &quot;四、批判性思考：遗产保护中应避免只见“样式”不见“机制”&quot;">​</a></h1><p>从调研结果看，当前对开平近代建筑的理解容易出现两个偏差。其一，是把“中西合璧”简单理解为形式拼贴，只注意拱券、柱式、山花等视觉上醒目的西式元素，而忽视它们与中式屋顶、题额、厅堂秩序及社会功能之间的关系。如此一来，建筑价值就容易被压缩为一种风格标签，真正支撑其意义的地方社会结构、礼制传统与生活方式则被遮蔽。</p><p>其二，是在遗产保护与展示中偏重“保存外观”，而忽略建筑语言背后的文化机制。若保护工作只关注建筑外立面、造型轮廓和局部修饰，而不重视题额文字、室内陈设、空间礼序、使用痕迹以及建筑与村落、街道之间的关系，那么所谓的保护便可能退化为表层风貌修缮。对于开平这类兼具建筑史价值与侨乡文化价值的遗产样本而言，真正需要保存的，不仅是构件本身，更是构件所承载的社会意义与文化关系。</p><p>因此，开平近代建筑的保护不应停留在“样式识别”层面，而应进一步转向“表达机制”的理解。只有将住宅中的身份建构、祠堂中的礼制更新、骑楼中的公共传播等问题一并纳入分析，才能更完整地把握这些建筑的遗产价值。换言之，开平近代建筑不是静态的历史图像，而是一套通过建筑语言组织文化认同的地方系统。</p><h1 id="五、结论" tabindex="-1">五、结论 <a class="header-anchor" href="#五、结论" aria-label="Permalink to &quot;五、结论&quot;">​</a></h1><p>通过对立园、仓东村与赤坎古镇的调研比较，可以看到，开平近代建筑的核心价值并不只在于中式与西式形式的并置，而在于二者在侨乡社会背景中持续发生对话，并通过建筑语言融合形成具有地方性的表达方式。立园住宅体现的是现代身份与传统归属之间的协商，仓东村公祠体现的是礼制空间在近代社会中的外观更新，赤坎骑楼体现的则是商业街道与公共形象的建构。三者共同表明，中西建筑文化在开平并非彼此排斥，而是在不同类型建筑中被重新组织、重新解释并重新赋予意义。</p><p>因此，开平近代建筑应被理解为一种“以建筑语言组织文化认同”的地方遗产样本，而不只是中西合璧的样式集合。对其进行研究和保护，也不应止于辨认柱式、山花或拱券等形式特征，更应关注这些形式如何进入地方生活，并参与身份、礼序和街区形象的建构。只有从这一层面理解开平建筑，才能真正把握其建筑史价值与文化遗产意义。</p><h1 id="六、附录-调研记录" tabindex="-1">六、附录：调研记录 <a class="header-anchor" href="#六、附录-调研记录" aria-label="Permalink to &quot;六、附录：调研记录&quot;">​</a></h1><h3 id="_6-1-摄影记录" tabindex="-1">6.1 摄影记录 <a class="header-anchor" href="#_6-1-摄影记录" aria-label="Permalink to &quot;6.1 摄影记录&quot;">​</a></h3><p>本报告共插入17张现场照片，主要分为住宅、公祠与骑楼三组类型。其中：</p><p>图1、图2展示立园住宅立面差异；<br> 图3—图5记录毓培别墅的外立面与室内空间特征；<br> 图6、图7呈现仓东村公祠的整体立面与构件特写；<br> 图8、图9展示赤坎古镇骑楼街景及立面局部；<br> 图10—图17对应住宅顶部构造、公祠内部空间以及骑楼连续界面的观察重点。</p><h3 id="_6-2-文献资料" tabindex="-1">6.2 文献资料 <a class="header-anchor" href="#_6-2-文献资料" aria-label="Permalink to &quot;6.2 文献资料&quot;">​</a></h3><ol><li>《华侨建筑文化研究》，华侨大学建筑学院，中国建筑工业出版社，2010</li><li>《开平碉楼》，广东省文物考古研究所，文物出版社，2007</li><li>《开平碉楼村落保护与利用研究》，华南理工大学出版社，2018</li></ol><p>报告撰写人：陈升逸<br> 报告完成时间：2026年4月5日<br> 字数统计：约4000字</p>',47)])])}const w=r(P,[["render",x]]);export{S as __pageData,w as default};
